import React from "react";
import { Link } from "react-router-dom";
import "./Home.css";

export default function Home() {
  const destinations = [
    {
      id: 1,
      name: "Goa",
      image: "https://source.unsplash.com/600x400/?goa,beach",
      description: "Tropical beaches and fun nightlife.",
    },
    {
      id: 2,
      name: "Manali",
      image: "https://source.unsplash.com/600x400/?mountain,manali",
      description: "Snowy mountains and cozy cottages.",
    },
    {
      id: 3,
      name: "Jaipur",
      image: "https://source.unsplash.com/600x400/?jaipur,palace",
      description: "Experience royal culture and forts.",
    },
  ];

  return (
    <div className="home-container">
      {/* Hero Section */}
      <section className="hero-section">
        <div className="hero-overlay">
          <h1 className="hero-title">Find Your Perfect Getaway 🏝️</h1>
          <p className="hero-subtitle">
            Book beautiful stays, unique experiences, and adventures worldwide.
          </p>
          <Link to="/booking-confirmation">
            <button className="book-btn">Book Now</button>
          </Link>
        </div>
      </section>

      {/* Destinations Section */}
      <section className="destinations">
        <h2 className="section-title">Popular Destinations</h2>
        <div className="destination-grid">
          {destinations.map((place) => (
            <div key={place.id} className="destination-card">
              <img src={place.image} alt={place.name} />
              <h3>{place.name}</h3>
              <p>{place.description}</p>
              <Link to="/booking-confirmation">
                <button className="explore-btn">Explore</button>
              </Link>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
}
